import type { MutableRefObject } from 'react';

import { DEFAULT_RESIZER_SIZE } from '../types/constants.js';

export const getResizerWrapperSize = (
  isVertical: boolean,
  legendResizeContainerRef: MutableRefObject<HTMLDivElement | null>,
) =>
  isVertical
    ? legendResizeContainerRef.current?.clientHeight ?? DEFAULT_RESIZER_SIZE
    : legendResizeContainerRef.current?.clientWidth ?? DEFAULT_RESIZER_SIZE;
